package org.jsoup.select;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.jsoup.select.steps"
)
public class CucumberTest {
}

package org.jsoup.select.steps;

import io.cucumber.java.en.*;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.select.Elements;
import java.util.List;
import java.util.ArrayList;

import static org.junit.Assert.*;

public class StepDefs {
    private Document document;
    private Elements result;
    private Exception exception;

    @Given("an HTML document with the following content:")
    public void an_html_document_with_the_following_content(String htmlContent) {
        document = Jsoup.parse(htmlContent);
    }

    @When("I select elements using the selector {string}")
    public void i_select_elements_using_the_selector(String selector) {
        try {
            result = document.select(selector);
            exception = null;
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("the selection should not throw a {string}")
    public void the_selection_should_not_throw_a(String exceptionName) {
        if (exception != null) {
            assertFalse("Expected no exception but got: " + exception.getClass().getSimpleName() + " - " + exception.getMessage(),
                       exception.getClass().getSimpleName().contains(exceptionName));
        }
    }

    @Then("the result should contain {int} elements")
    public void the_result_should_contain_elements(Integer expectedCount) {
        assertEquals("Expected " + expectedCount + " elements but got " + result.size(), 
                     expectedCount.intValue(), result.size());
    }

    @Then("the first element should be the {string} with text {string}")
    public void the_first_element_should_be_the_with_text(String tagName, String expectedText) {
        Element firstElement = result.first();
        assertNotNull("First element should not be null", firstElement);
        assertEquals("Expected tag " + tagName + " but got " + firstElement.tagName(), 
                     tagName, firstElement.tagName());
        assertEquals("Expected text " + expectedText + " but got " + firstElement.text(), 
                     expectedText, firstElement.text());
    }

    @Then("the second element should be the {string} with text {string}")
    public void the_second_element_should_be_the_with_text(String tagName, String expectedText) {
        assertNotNull("Result should not be null", result);
        assertTrue("Result should have at least 2 elements", result.size() >= 2);

        Element secondElement = result.get(1);  // 0-indexed, so element at index 1 is the second
        assertEquals("Expected tag " + tagName + " but got " + secondElement.tagName(), 
                     tagName, secondElement.tagName());
        assertEquals("Expected text " + expectedText + " but got " + secondElement.text(), 
                     expectedText, secondElement.text());
    }
}
